// MainActivity.kt
package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.ImageView
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class MainActivity : AppCompatActivity() {

    private lateinit var sharedContentTextView: TextView
    private lateinit var sharedImageView: ImageView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        sharedContentTextView = findViewById(R.id.sharedContentTextView)
        sharedImageView = findViewById(R.id.sharedImageView)

        handleIncomingIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleIncomingIntent(it) }
    }

    private fun handleIncomingIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> {
                if (intent.type?.startsWith("text/") == true) {
                    handleSharedText(intent)
                } else if (intent.type?.startsWith("image/") == true) {
                    handleSharedImage(intent)
                }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                if (intent.type?.startsWith("image/") == true) {
                    handleSharedMultipleImages(intent)
                }
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        if (sharedText != null) {
            if (isUrl(sharedText)) {
                processUrl(sharedText)
            } else {
                processText(sharedText)
            }
        } else {
            Toast.makeText(this, "No text content found", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        if (imageUri != null) {
            processImage(imageUri)
        } else {
            Toast.makeText(this, "No image found", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleSharedMultipleImages(intent: Intent) {
        val imageUris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
        if (imageUris != null && imageUris.isNotEmpty()) {
            processMultipleImages(imageUris)
        } else {
            Toast.makeText(this, "No images found", Toast.LENGTH_SHORT).show()
        }
    }

    private fun isUrl(text: String): Boolean {
        return text.startsWith("http://") || text.startsWith("https://")
    }

    private fun processUrl(url: String) {
        sharedContentTextView.text = "Shared URL:\n$url"
        sharedImageView.setImageDrawable(null)
        Toast.makeText(this, "URL received and processed", Toast.LENGTH_SHORT).show()
    }

    private fun processText(text: String) {
        sharedContentTextView.text = "Shared Text:\n$text"
        sharedImageView.setImageDrawable(null)
        Toast.makeText(this, "Text received and processed", Toast.LENGTH_SHORT).show()
    }

    private fun processImage(imageUri: Uri) {
        sharedContentTextView.text = "Shared Image:\n${imageUri.toString()}"
        sharedImageView.setImageURI(imageUri)
        Toast.makeText(this, "Image received and processed", Toast.LENGTH_SHORT).show()
    }

    private fun processMultipleImages(imageUris: List<Uri>) {
        sharedContentTextView.text = "Shared ${imageUris.size} Images:\n${imageUris.joinToString("\n")}"
        if (imageUris.isNotEmpty()) {
            sharedImageView.setImageURI(imageUris[0])
        }
        Toast.makeText(this, "${imageUris.size} images received and processed", Toast.LENGTH_SHORT).show()
    }
}